"use strict";(self.webpackChunk_5_shangzhi_github_io=self.webpackChunk_5_shangzhi_github_io||[]).push([[477],{10:function(n){n.exports=JSON.parse('{"blogPosts":[{"id":"Android-Emulator-running-on-Apple-M1-machines-without-Android-Studio","metadata":{"permalink":"/blog/Android-Emulator-running-on-Apple-M1-machines-without-Android-Studio","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/Android Emulator running on Apple M1 machines (without installing Android Studio).md","source":"@site/blog/Android Emulator running on Apple M1 machines (without installing Android Studio).md","title":"How to install Android Emulator on Apple M1 machines without  Android Studio","description":"How to install Android Emulator on Apple M1 machines without Android Studio","date":"2022-06-21T01:33:35.000Z","formattedDate":"2022\u5e746\u670821\u65e5","tags":[],"readingTime":1.665,"truncated":false,"authors":[{"name":"\u5434\u5c1a\u667a","title":"\u4e95\u86d9\u60ca\u68a6\u4eba","url":"https://github.com/5shangzhi","imageURL":"https://avatars.githubusercontent.com/u/103982059","key":"5shangzhi"}],"frontMatter":{"slug":"Android-Emulator-running-on-Apple-M1-machines-without-Android-Studio","title":"How to install Android Emulator on Apple M1 machines without  Android Studio","authors":"5shangzhi","description":"How to install Android Emulator on Apple M1 machines without Android Studio","image":"https://5shangzhi.github.io/img/frog-200.png","keywords":["Android","Emulator","Apple","M1","MacOS","\u4e95\u86d9\u60ca\u68a6\u4eba","\u5434\u5c1a\u667a"]},"nextItem":{"title":"\u5979\u4e3e\u8d77\u4e86\u5c0f\u624b\uff0c\u8fd8\u6709\u5979\u7684\u6bdb\u7ed2\u5154\uff01","permalink":"/blog/wusz-2022-06-17"}},"content":"Android Studio is a big Application. If you are not an Android programmer, you don\'t need it. But sometimes you need an Android Emulator running on your Apple M1 machines. So this document is for you.\\n\\nIt works well on my Macbook.\\n\\n![\u4e95\u86d9\u60ca\u68a6\u4eba](images/2022-06-21/android-emulator-on-macos-m1.png)\\n\\n### 1. Install android command line tools\\n\\n```sh\\n$ brew install android-commandlinetools\\n```\\n\\nYou will get **sdkmanager** and **avdmanager** available, but they need Java.\\n\\n### 2. Install java if you haven\'t it\\n\\n```sh\\n$ brew install --cask temurin\\n```\\n\\n### 3. You can verify that sdkmanager works:\\n\\n```sh\\n$ sdkmanager --version\\n```\\n\\n### 4. Set PATH environment variable in file `~/.zshrc` or `~/.bashrc`\\n\\n```sh\\n$ mkdir -p $HOME/Library/Android/sdk\\n```\\n\\n```sh\\nexport ANDROID_SDK_ROOT=$HOME/Library/Android/sdk\\nif [ -d $ANDROID_SDK_ROOT ]\\nthen\\n  PATH=\\"$ANDROID_SDK_ROOT/emulator:$ANDROID_SDK_ROOT/platform-tools:$PATH\\"\\nfi\\n```\\n\\n```sh\\n$ source ~/.zshrc\\n```\\n\\n### 5. Download Android components:\\n\\n```sh\\n$ sdkmanager --install --sdk_root=$ANDROID_SDK_ROOT \\\\\\n\\"platform-tools\\" \\"emulator\\" \\\\\\n\\"platforms;android-30\\" \\\\\\n\\"system-images;android-30;google_apis_playstore;arm64-v8a\\"\\n```\\n\\nMaybe you need run this command if you encounter a MacOS system permission problem: \\n\\n```sh\\n$ xattr -dr com.apple.quarantine emulator/\\n```\\n\\n### 6. Create a virtual Android devcie to run in the emulator.\\n\\nNote: --package `params`, the **params** value is the name you downloaded via sdkmanager in the previous step.\\n\\n```sh\\n$ avdmanager create avd \\\\\\n--name \\"android30\\" --device \\"pixel\\" \\\\\\n--package \\"system-images;android-30;google_apis_playstore;arm64-v8a\\"\\n```\\n\\nYou can create as many virtual devices as you like. Just repeat the step above with different parameters.\\n\\n### 7. Normally, you need enable hardware keyboard\\n\\nBy default, your computer keyboard is not available in the emulator you just created. You can enable it in this file: \xa0`~/.android/avd/android30.avd/config.ini` (replace\xa0`android30`\xa0with the name of your device).\\n\\n```diff\\n- hw.keyboard = no\\n- hw.keyboard.lid = yes\\n+ hw.keyboard = yes\\n+ hw.keyboard.lid = no\\nhw.keyboard.charmap = qwerty2\\n```\\n\\n### 8. Now, It\'s time to start your emulator.\\n\\n```sh\\n$ emulator -avd android30\\n```\\n\\n### 9. You can install you app via `adb`\\n\\n```sh\\n$ adb install my-app.apk\\n```\\n\\n### APPENDIX: Reference link of this document.\\n\\n1. https://bajtos.net/posts/2021-12-17-apple-m1-android-emulator/\\n2. https://stackoverflow.com/a/34799349"},{"id":"wusz-2022-06-17","metadata":{"permalink":"/blog/wusz-2022-06-17","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/\u5979\u4e3e\u8d77\u4e86\u5c0f\u624b\uff0c\u8fd8\u6709\u5979\u7684\u6bdb\u7ed2\u5154\uff01.md","source":"@site/blog/\u5979\u4e3e\u8d77\u4e86\u5c0f\u624b\uff0c\u8fd8\u6709\u5979\u7684\u6bdb\u7ed2\u5154\uff01.md","title":"\u5979\u4e3e\u8d77\u4e86\u5c0f\u624b\uff0c\u8fd8\u6709\u5979\u7684\u6bdb\u7ed2\u5154\uff01","description":"\u6761\u4ef6\u53cd\u5c04\u4e0e\u9a6f\u670d","date":"2022-06-17T02:00:17.000Z","formattedDate":"2022\u5e746\u670817\u65e5","tags":[],"readingTime":2.455,"truncated":false,"authors":[{"name":"\u5434\u5c1a\u667a","title":"\u4e95\u86d9\u60ca\u68a6\u4eba","url":"https://github.com/5shangzhi","imageURL":"https://avatars.githubusercontent.com/u/103982059","key":"5shangzhi"}],"frontMatter":{"slug":"wusz-2022-06-17","title":"\u5979\u4e3e\u8d77\u4e86\u5c0f\u624b\uff0c\u8fd8\u6709\u5979\u7684\u6bdb\u7ed2\u5154\uff01","authors":"5shangzhi","description":"\u6761\u4ef6\u53cd\u5c04\u4e0e\u9a6f\u670d","image":"https://5shangzhi.github.io/img/frog-200.png","keywords":["\u6761\u4ef6\u53cd\u5c04","\u9a6f\u670d","\u6838\u9178\u68c0\u6d4b","\u4e95\u86d9\u60ca\u68a6\u4eba","\u5434\u5c1a\u667a"]},"prevItem":{"title":"How to install Android Emulator on Apple M1 machines without  Android Studio","permalink":"/blog/Android-Emulator-running-on-Apple-M1-machines-without-Android-Studio"},"nextItem":{"title":"\u662f\u8def\u7684\u95ee\u9898\uff1f","permalink":"/blog/wusz-2022-06-16"}},"content":"\u6709\u670b\u53cb\u8f6c\u53d1\u4e86\u4e00\u4e2a\u89c6\u9891\uff1a\u4e00\u4e2a\u5c0f\u5973\u5b69\u51d1\u5230\u62ff\u7740\u624b\u6e29\u67aa\u7684\u7269\u4e1a\u5de5\u4f5c\u4eba\u5458\u9762\u524d\uff0c\u4e3b\u52a8\u8ba9\u4ed6\u7ed9\u81ea\u5df1\u6d4b\u624b\u6e29\u3002\u5de5\u4f5c\u4eba\u5458\u5f88\u597d\uff0c\u4e0d\u4f46\u7ed9\u5979\u4e00\u4e00\u6d4b\u8fc7\uff0c\u8fde\u5c0f\u5973\u5b69\u4e3e\u8d77\u6765\u7684\u6bdb\u7ed2\u5154\u4e5f\u7ed9\u6d4b\u4e86\u3002\\n\\n![\u4e95\u86d9\u60ca\u68a6\u4eba](images/2022-06-17/1.png)\\n\\n\u4f30\u8ba1\u4f1a\u6709\u4e0d\u5c11\u4eba\u8ba4\u4e3a\u573a\u9762\u5f88\u6e29\u99a8\uff0c\u5927\u53d4\u5f88nice\uff0c\u5c0f\u5973\u5b69\u5f88\u53ef\u7231\u3002\u662f\u7684\uff0c\u8fd9\u4e9b\u6211\u90fd\u627f\u8ba4\u3002\u4f46\u6211\u770b\u7740\u5f88\u4e0d\u597d\u53d7\u3002\u5979\u7684\u7ae5\u5e74\u91cc\u9762\u672c\u8be5\u6ca1\u6709\u8fd9\u4e9b\u3002\\n\\n\u6211\u8fd8\u770b\u8fc7\u4e00\u4e9b\u89c6\u9891\uff0c\u5b69\u5b50\u73a9\u8fc7\u5bb6\u5bb6\uff0c\u8ba9\u5bb6\u957f\u548c\u73a9\u5177\u4e00\u8d77\u6392\u961f\uff0c\u5230\u4ed6\u90a3\u91cc\u505a\u6838\u9178\u68c0\u6d4b\u3002\u90a3\u961f\u4f0d\u8001\u957f\u4e86\uff0c\u8f6c\u7740\u5708\u5730\u4ece\u5ba2\u5385\u6392\u5230\u4e86\u5bb6\u95e8\u53e3\u3002\u89c6\u9891\u62cd\u5f97\u633a\u6b22\u4e50\u7684\uff0c\u7136\u800c\uff0c\u4e0e\u5c0f\u5973\u5b69\u6d4b\u624b\u6e29\u7684\u89c6\u9891\u4e00\u6837\uff0c\u4e0d\u80fd\u7ec6\u601d\u3002\\n\\n\u4f30\u8ba1\u5f88\u591a\u4eba\u90fd\u4e0d\u66fe\u6599\u5230\uff0c\u4ed6\u4eec\u5c06\u5e7c\u5c0f\u7684\u751f\u547d\u5e26\u5230\u8fd9\u4eba\u95f4\uff0c\u5374\u7ed9\u4e86\u5b69\u5b50\u4e00\u4e2a\u5982\u6b64\u7684\u4e16\u754c\u3002\\n\\n\u4e0e\u6b64\u76f8\u5e94\u7684\uff0c\u8fd8\u6709\u4e00\u4e2a\u89c6\u9891\uff1a\\n\\n![\u4e95\u86d9\u60ca\u68a6\u4eba](images/2022-06-17/2.jpeg)\\n\\n\u4eba\u4eec\u5df2\u7ecf\u4e0d\u518d\u5728\u4e4e\u90a3\u4e2a\u5750\u5728\u90a3\u91cc\u7684\u4eba\u662f\u8c01\u4e86\uff0c\u90fd\u8feb\u4e0d\u53ca\u5f85\u5730\u201c\u81ea\u8bc1\u6e05\u767d\u201d\u3002\\n\\n\u8fd9\u4e2a\u89c6\u9891\u4e2d\uff0c\u6700\u8ba9\u6211\u624e\u5fc3\u7684\u8fd8\u662f\u8fd9\u4e00\u5e55\uff1a\u5927\u4eba\u4e3b\u52a8\u51fa\u793a\u624b\u673a\uff0c**\u5728\u5c0f\u5973\u5b69\u7684\u9762\u524d\u4f38\u8fc7**\uff0c\u7ed9\u5750\u5728\u90a3\u91cc\u7684\u4eba\u770b\u3002\u6b63\u662f\u8fd9\u8eab\u4f53\u529b\u884c\u7684\u8eab\u6559\uff0c\u5927\u4eba\u5df2\u7ecf\u5c06\u4e00\u9897\u79cd\u5b50\u57cb\u8fdb\u4e86\u5b69\u5b50\u7684\u5fc3\u91cc\u3002\\n\\n\u6211\u4e0d\u5f97\u4e0d\u627f\u8ba4\uff0c\u8fd9\u56fd\u7684\u9632\u75ab\u771f\u7684\u5f88\u6210\u529f\u3002\\n\\n\u6709\u670b\u53cb\u8bf4\u8fd9\u662f\u201c\u5df4\u666e\u6d1b\u592b\u7684\u72d7\uff0c\u6700\u751f\u52a8\u7684\u4f8b\u5b50\u201d\uff0c\u6211\u8d5e\u540c\u3002\u4f46\u662f\uff0c\u8fd9\u4e0d\u4ec5\u4ec5\u662f\u6761\u4ef6\u53cd\u5c04\uff0c\u66f4\u662f\u9a6f\u670d\u7684\u4f8b\u5b50\u3002\\n\\n\u4e0d\u8bba\u4ec0\u4e48\u6837\u7684\u4eba\u5750\u5728\u90a3\u628a\u6905\u5b50\u4e0a\uff0c\u4ed6\u5c31\u662f\u6743\u529b\u7684\u8c61\u5f81\uff0c\u6211\u4eec\u5c31\u8981\u5411\u4ed6\u81ea\u8bc1\u6e05\u767d\u3002\\n\\n\u90a3\u4e2a\u62b1\u7740\u6bdb\u7ed2\u5154\uff0c\u4e3b\u52a8\u51d1\u5230\u5de5\u4f5c\u4eba\u5458\u9762\u524d\u7684\u5c0f\u5973\u5b69\uff0c\u5979\u4e0d\u4f46\u8981\u81ea\u8bc1\u6e05\u767d\uff0c\u8fd8\u8981\u4e3a\u5979\u7684\u5154\u5b9d\u5b9d\u8bc1\u660e\u3002\\n\\n![\u4e95\u86d9\u60ca\u68a6\u4eba](https://5shangzhi.github.io/img/frog.jpeg)"},{"id":"wusz-2022-06-16","metadata":{"permalink":"/blog/wusz-2022-06-16","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/\u662f\u8def\u7684\u95ee\u9898\uff1f.md","source":"@site/blog/\u662f\u8def\u7684\u95ee\u9898\uff1f.md","title":"\u662f\u8def\u7684\u95ee\u9898\uff1f","description":"\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7684\u672a\u6765","date":"2022-06-17T02:00:17.000Z","formattedDate":"2022\u5e746\u670817\u65e5","tags":[],"readingTime":12.985,"truncated":false,"authors":[{"name":"\u5434\u5c1a\u667a","title":"\u4e95\u86d9\u60ca\u68a6\u4eba","url":"https://github.com/5shangzhi","imageURL":"https://avatars.githubusercontent.com/u/103982059","key":"5shangzhi"}],"frontMatter":{"slug":"wusz-2022-06-16","title":"\u662f\u8def\u7684\u95ee\u9898\uff1f","authors":"5shangzhi","description":"\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7684\u672a\u6765","image":"https://5shangzhi.github.io/img/frog-200.png","keywords":["\u65e0\u4eba\u9a7e\u9a76","\u672a\u6765","\u601d\u7ef4\u8bad\u7ec3","\u4e95\u86d9\u60ca\u68a6\u4eba","\u5434\u5c1a\u667a"]},"prevItem":{"title":"\u5979\u4e3e\u8d77\u4e86\u5c0f\u624b\uff0c\u8fd8\u6709\u5979\u7684\u6bdb\u7ed2\u5154\uff01","permalink":"/blog/wusz-2022-06-17"},"nextItem":{"title":"\u9762\u5bf9\u66b4\u5f92\uff0c\u5f31\u8005\u4e34\u573a\u8be5\u5982\u4f55\u53cd\u5e94\uff1f","permalink":"/blog/wusz-2022-06-13"}},"content":"\u672c\u6587\u63a2\u8ba8\u4e24\u4e2a\u95ee\u9898\uff0c\u91cd\u70b9\u5728\u7b2c\u4e8c\u4e2a\u3002\\n\\n\u7b2c\u4e00\u4e2a\u95ee\u9898\uff1a**\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u5c06\u4f1a\u5728\u54ea\u4e2a\u56fd\u5bb6\u7387\u5148\u63a8\u51fa\uff1f**\\n\\n\u6211\u731c\u6709\u76f8\u5f53\u4e00\u90e8\u5206\u4eba\u4f1a\u5c06\u7f8e\u56fd\u4f5c\u4e3a\u7b54\u6848\u3002\\n\\n\u4ece\u6280\u672f\u4e0a\u800c\u8a00\uff0c\u7f8e\u56fd\u786e\u5b9e\u5177\u5907\u8fd9\u6837\u7684\u5b9e\u529b\uff0c\u6211\u751a\u81f3\u76f8\u4fe1Google\u7684\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u5df2\u7ecf\u5177\u5907\u4e86\u4e0a\u8def\u7684\u80fd\u529b\u3002\u4f46\u662f\uff0c\u4ed6\u4eec\u5f88\u53ef\u80fd\u6709\u4e00\u5c42\u725b\u76ae\u7eb8\u96be\u4ee5\u6345\u7834\u3002\\n\\n\u7387\u5148\u63a8\u51fa\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7684\u5927\u6982\u7387\u4f1a\u662f\u4e00\u4e2a**\u72ec\u88c1\u56fd\u5bb6**\uff0c\u7f8e\u82f1\u65e5\u6cd5\u7b49\u56fd\u90fd\u4e0e\u4e4b\u4e0d\u7b26\u3002\\n\\n\u4e3a\u4ec0\u4e48\u4f1a\u662f\u8fd9\u6837\uff1f\\n\\n\u95ee\u9898\u4e0d\u662f\u51fa\u5728\u6280\u672f\u4e0a\uff0c\u800c\u662f\u5728\u4f26\u7406\u4e0e\u6cd5\u5f8b\u4e0a\u3002\u8fd9\u4e5f\u662f\u72ec\u88c1\u56fd\u5bb6\u7684\u201c\u597d\u5904\u201d\uff0c\u5b83\u4eec\u8fde\u6cd5\u5f8b\u90fd\u53ef\u4ee5\u76f4\u63a5\u65e0\u89c6\uff0c\u66f4\u522b\u8bf4\u4ec0\u4e48\u4f26\u7406\u4e86\u3002\\n\\n\u54f2\u5b66\u4e0a\u6709\u4e2a\u201c\u7535\u8f66\u96be\u9898\u201d\uff0c\u6211\u4e4b\u524d\u7684\u6587\u7ae0\u6709\u63d0\u5230\u8fc7\uff08\u5173\u4e8e\u6b66\u6c49\u75ab\u60c5\u4e4b\u521d\u5c01\u57ce\u7684\u8ba8\u8bba\uff09\uff0c\u8fd9\u9053\u96be\u9898\u5f80\u5f80\u662f\u4f5c\u4e3a\u201c\u601d\u60f3\u5b9e\u9a8c\u201d\u6765\u63a2\u8ba8\u7684\uff0c\u7136\u800c\uff0c\u5728\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7684\u843d\u5730\u8fd0\u884c\u4e0a\uff0c\u5374\u6210\u4e86\u5b9e\u9645\u7684\u95ee\u9898\uff0c\u6210\u4e86\u5fc5\u987b\u8981\u9762\u5bf9\u548c\u89e3\u51b3\u7684\u95ee\u9898\u3002\u7136\u800c\uff0c\u6211\u4eec\u77e5\u9053\uff0c\u8fd9\u9053\u9898\u662f\u201c\u65e0\u89e3\u201d\u7684\uff0c\u5b83\u6ca1\u6709**\u6807\u51c6**\u7b54\u6848\u3002\\n\\n\u7b80\u5355\u8bf4\u4e00\u4e0b\u7535\u8f66\u96be\u9898\uff1a\u4f60\u662f\u4e00\u8f86\u7535\u8f66\u7684\u53f8\u673a\uff0c\u6240\u9a7e\u9a76\u7684\u8f66\u8f86\u5728\u8f68\u9053\u4e0a\u5feb\u901f\u884c\u8fdb\u3002\u4f60\u7a81\u7136\u53d1\u73b0\u524d\u65b9\u8f68\u9053\u4e0a\u67095\u4e2a\u5b69\u5b50\u5728\u73a9\u800d\uff0c\u4ed6\u4eec\u5bf9\u4e8e\u8feb\u5728\u7709\u776b\u7684\u5371\u9669\u65e0\u77e5\u65e0\u89c9\uff0c\u800c\u4f60\u7684\u5239\u8f66\u5931\u7075\u4e86\uff08\u6216\u8005\u7531\u4e8e\u901f\u5ea6\u5feb\u3001\u8ddd\u79bb\u77ed\uff0c\u5239\u4e5f\u5239\u4e0d\u4f4f\uff09\uff0c\u8fd9\u65f6\u4f60\u53d1\u73b0\u524d\u65b9\u6709\u4e00\u4e2a\u5c94\u9053\uff0c\u4f60\u53ef\u4ee5\u8f6c\u5411\u8fdb\u5165\u53e6\u4e00\u94c1\u8f68\uff0c\u4f46\u662f\uff0c\u90a3\u91cc\u4e5f\u67091\u4e2a\u5b69\u5b50\u5728\u94c1\u8f68\u4e0a\u73a9\u800d\uff0c\u4f60\u4f1a\u4e0d\u4f1a\u8f6c\u5411\uff1f\uff08\u5b69\u5b50\u53ef\u4ee5\u6362\u6210\u94c1\u9053\u5de5\uff0c\u6216\u8005\uff0c\u5c31\u662f\u62bd\u8c61\u7684\u4eba\uff09\\n\\n\u5f88\u591a\u4eba\u5728\u521d\u89c1\u8fd9\u4e2a\u95ee\u9898\u65f6\u90fd\u4f1a\u9009\u62e9\u8f6c\u5411\uff0c\u4ed6\u4eec\u4f1a\u7b80\u5355\u6839\u636e\u4eba\u6570\u6765\u5224\u65ad\uff0c\u8fd9\u662f\u529f\u5229\u7684\u7b97\u8ba1\u4f7f\u7136\u3002\u7136\u800c\uff0c\u5982\u679c\u90a3\u4e00\u4e2a\u4eba\u662f\u4f60\u7684\u5b69\u5b50\uff0c\u6216\u8005\u662f\u4f60\u7684\u5bb6\u4eba\uff0c\u66f4\u751a\u8005\u5c31\u662f\u4f60 \u2014\u2014 \u4f60\u8fd8\u4f1a\u8f6c\u5411\u4e48\uff1f\u54ea\u6015\u662f\u51fa\u4e8e\u529f\u5229\u7b97\u8ba1\uff0c\u5018\u82e5\u90a3\u4e94\u4e2a\u662f\u666e\u901a\u5de5\u4eba\uff0c\u800c\u90a3\u4e00\u4e2a\u5374\u662f\u9876\u5c16\u7684\u79d1\u5b66\u5bb6\uff0c\u4f60\u8fd8\u4f1a\u9009\u62e9\u8f6c\u5411\u4e48\uff1f\u4e3a\u4e86\u8ba9\u4eba\u4eec\u6df1\u601d\uff0c\u7535\u8f66\u96be\u9898\u8fd8\u6709\u5176\u4ed6\u7684\u53d8\u4f53\uff0c\u8fd9\u91cc\u5c31\u4e0d\u5c55\u5f00\u4e86\u3002\\n\\n\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u662f\u8981\u5148\u8bbe\u5b9a\u7b97\u6cd5\u7684\uff0c\u5f53\u524d\u65b9\u51fa\u73b0\u72b6\u51b5\u65f6\uff0c\u5b83\u8be5\u600e\u4e48\u505a\uff0c\u8fd9\u90fd\u9700\u8981\u63d0\u524d\u8bbe\u8ba1\u597d\u3002\u4e8e\u662f\uff0c\u7535\u8f66\u96be\u9898\u5c31\u6210\u4e86\u7a0b\u5e8f\u5458\u7ed5\u4e0d\u53bb\u7684\u574e \u2014\u2014 \u603b\u4e0d\u80fd\u968f\u673a\u649e\u4e00\u4e2a\u5427\uff1f\u90a3\u4e5f\u592a\u4e0d\u8d1f\u8d23\u4efb\u4e86\uff0c\u771f\u8fd9\u6837\u505a\u4e86\u80af\u5b9a\u4f1a\u906d\u9047\u5f3a\u70c8\u7684\u8d28\u7591\u3002\u800c\u4e00\u65e6\u7b97\u6cd5\u6d89\u53ca\u5bf9**\u67d0\u4e00\u6761\u4ef6**\u6765\u8fdb\u884c\u5224\u65ad\uff0c\u4ece\u800c\u51b3\u5b9a\u662f\u5426\u8f6c\u5411\uff0c**\u6761\u4ef6\u672c\u8eab**\u5c31\u662f\u9762\u4e34\u7535\u8f66\u96be\u9898\u3002\u7a0b\u5e8f\u5458\u81ea\u7136\u662f\u80cc\u4e0d\u52a8\u8fd9\u4e48\u5927\u7684\u9505\uff0c\u4f46\u516c\u53f8\u8981\u5bf9\u6b64\u8d1f\u8d23\uff0c\u8fd9\u6700\u7ec8\u4fbf\u4f1a\u4f53\u73b0\u5728\u4f26\u7406\u4e0e\u6cd5\u5f8b\u4e0a \u2014\u2014 \u5982\u4f55\u5224\u65ad\u524d\u65b9\u9053\u8def\u4e0a\u201c\u969c\u788d\u7269\u201d\u7684\u4ef7\u503c\u3002\\n\\n\u8fd9\u4e00\u4ef7\u503c\u5224\u65ad\u672c\u8eab\u5c31\u662f\u9677\u9631\uff0c\u4e00\u65e6\u5224\u65ad\uff0c\u4fbf\u4f1a\u9677\u5165\u56f0\u5883\u3002\\n\\n\u6709\u4e2a\u5173\u4e8e\u9a7e\u8003\u7684\u7b11\u8bdd\uff0c\u8003\u5b98\u95ee\u8003\u751f\uff1a\u201c\u8f66\u8f86\u884c\u9a76\u4e2d\uff0c\u524d\u65b9\u9053\u8def\u4e0a\u6709\u4e00\u4e2a\u4eba\u548c\u4e00\u6761\u72d7\uff0c\u4f60\u9009\u62e9\u649e\u8c01\uff1f\u201d \u8003\u751f\u5f53\u7136\u9009\u62e9\u649e\u72d7\uff0c\u8003\u5b98\u5c31\u9a82\uff1a\u201c\u8e29\u5239\u8f66\u554a\uff0c\u8822\u8d27\uff01\u201d\u9762\u5bf9\u8fd9\u79cd\u9677\u9631\uff0c\u8003\u751f\u5f53\u54ea\u6562\u8fd8\u5634\u8d28\u7591\u95ee\u9898 \u2014\u2014 \u5239\u4e0d\u4f4f\u600e\u4e48\u529e\uff1f\\n\\n\u5982\u679c\u7b97\u6cd5\u7684\u8bbe\u5b9a\u5c31\u662f\u649e\u72d7\uff0c\u90a3\u4e9b\u7231\u72d7\u4eba\u58eb\u8fd8\u80fd\u653e\u8fc7\u8fd9\u7b97\u6cd5\u7684\u5236\u5b9a\u8005\uff1f\u4ed6\u4eec\u4f1a\u8bf4\u72d7\u662f\u4eba\u7c7b\u6700\u5fe0\u8bda\u7684\u670b\u53cb\uff0c\u6bd4\u5f88\u591a\u4eba\u90fd\u5fe0\u8bda\u2026\u2026\u4e8e\u662f\uff0c\u5c06\u8fd9\u5bb6\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7684\u516c\u53f8\u544a\u4e0a\u6cd5\u5ead\u3002\u8fd9\u6837\u7684\u4e8b\u60c5\u5728\u90a3\u4e9b\u6c11\u4e3b\u56fd\u5bb6\u662f\u663e\u800c\u6613\u89c1\u7684\u3002\\n\\n\u800c\u5728\u72ec\u88c1\u56fd\u5bb6\uff0c\u4ed6\u4eec\u538b\u6839\u513f\u5c31\u4e0d\u4f1a\u8c08\u53ca\u7b97\u6cd5\u8bbe\u5b9a\u95ee\u9898\uff0c\u4f60\u8fd8\u60f3\u7533\u8bf7\u516c\u5f00\u8fd9\u4e00\u7b97\u6cd5\u903b\u8f91\uff1f\u95e8\u90fd\u6ca1\u6709\uff0c\u4e00\u53e5\u201c\u673a\u5bc6\u201d\u5c31\u628a\u4f60\u7ed9\u6253\u53d1\u4e86\uff01\\n\\n\u7b2c\u4e8c\u4e2a\u95ee\u9898\u662f\u6211\u6628\u5929\u770b\u4e66\u65f6\u7684\u601d\u8003\u3002\\n\\n\u90a3\u662f\u4e00\u672c\u56fe\u4e66\u9986\u501f\u6765\u7684\u4e66\u3002\u501f\u4e66\u65f6\u7531\u4e8e\u8d76\u65f6\u95f4\uff0c\u5c31\u53ea\u770b\u4e86\u4e0b\u4e66\u540d\u4e0e\u76ee\u5f55\uff0c\u53c8\u662f\u6700\u540e\u62ff\u7684\u4e00\u672c\uff0c\u6709\u70b9\u51d1\u6570\u7684\u611f\u89c9\u3002\\n\\n\u4e66\u4e2d\u8c08\u5230\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7684\u672a\u6765\u3002\u4f5c\u8005\u7684\u89c6\u89d2\u8fd8\u662f\u4e0d\u9519\u7684\uff0c\u4ed6\u4ece\u6c7d\u8f66\u7684\u51fa\u73b0\u4ee5\u53ca\u53d1\u5c55\u53f2\u6765\u5206\u6790\u95ee\u9898\uff0c\u4ece\u800c\u9884\u6d4b\u8d70\u52bf\u3002\\n\\n![\u4e95\u86d9\u60ca\u68a6\u4eba](images/2022-06-16/1.png)\\n\\n\u4f5c\u4e3a\u6279\u5224\u6027\u601d\u7ef4\u8bad\u7ec3\uff0c\u54b1\u4eec\u7684\u89c4\u77e9\u7167\u65e7\uff0c\u8fd9\u91cc\u6709\u514d\u8d39\u76845\u5206\u949f\u9001\u7ed9\u4f60\uff0c\u8bf7\u5148\u60f3\u4e00\u60f3\uff0c\u95ee\u9898\u51fa\u5728\u54ea\u91cc\uff1f\\n\\n![\u4e95\u86d9\u60ca\u68a6\u4eba](https://5shangzhi.github.io/img/cloud.jpeg)\\n\\n\u4f5c\u8005\u4f3c\u4e4e\u641e\u6df7\u4e86\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7814\u53d1\u7684\u76ee\u7684\uff0c\u597d\u50cf\u65e0\u4eba\u9a7e\u9a76\u662f\u4e3a\u4e86\u9ad8\u901f\u3002\\n\\n\u4ed6\u7684\u903b\u8f91\u662f\uff1a\u9a6c\u8f66\u6c7d\u8f66\u6df7\u884c\uff0c\u9a6c\u8f66\u59a8\u788d\u4e86\u6c7d\u8f66\uff08\u63d0\u901f\uff09\uff0c\u6c7d\u8f66\u5f88\u5403\u4e8f\uff0c\u4e8e\u662f\u6c7d\u8f66\u5229\u7528\u901f\u5ea6\u4f18\u52bf\u6765\u7529\u5f00\u9a6c\u8f66\uff0c\u4ece\u800c\u201c\u7279\u7acb\u72ec\u884c\u201d\u3002\u4ed6\u8bf4\uff0c\u5efa\u8bbe\u9ad8\u901f\u516c\u8def\u201c\u80cc\u540e\u7684\u76ee\u7684\u662f\u4e0d\u8ba9\u6c7d\u8f66\u4e0e\u9a6c\u8f66\u6df7\u5728\u4e00\u8d77\u884c\u9a76\u201d \u2014\u2014 \u8fd9\u5c31\u6709\u70b9\u641e\u7b11\u4e86\uff0c\u4f60\u770b\u89c1\u8fd8\u6709\u51e0\u8f86\u9a6c\u8f66\u5728\u8def\u4e0a\u884c\u9a76\uff1f\u54ea\u6015\u662f\u5728\u666e\u901a\u9053\u8def\u4e0a\uff0c\u9a6c\u8f66\u4e5f\u51e0\u4e4e\u7edd\u8ff9\u4e86\u3002\\n\\n\u6240\u4ee5\uff0c\u4ed6\u8fd9\u91cc\u7684\u201c\u9a6c\u8f66\u201d\u53ea\u80fd\u53d6\u5e7f\u4e49\u6216\u6bd4\u55bb\u4e49\u6765\u7406\u89e3\uff08\u5373\u4fbf\u4f5c\u8005\u6ca1\u6709\u8fd9\u610f\u601d\uff09\uff0c\u662f\u6307\u201c\u4f4e\u901f\u7684\u884c\u9a76\u8f66\u8f86\u201d\uff0c\u5373\u201c\u4e0d\u8ba9\u6c7d\u8f66\u4e0e\u4f4e\u901f\u4ea4\u901a\u5de5\u5177\u6df7\u5728\u4e00\u8d77\u884c\u9a76\u201d\uff0c\u4f46\u662f\uff0c\u96be\u9053\u8fd9\u5c31\u662f\u5efa\u8bbe\u9ad8\u901f\u516c\u8def\u7684\u76ee\u7684\uff1f\\n\\n\u5f88\u5bb9\u6613\u5c31\u80fd\u627e\u5230\u53cd\u4f8b\uff1a\u6469\u6258\u8f66\u4e0d\u4e5f\u80fd\u5f00\u5230120km/h\u4e48\uff0c\u4e3a\u4f55\u5374\u4e0d\u5141\u8bb8\u5b83\u4eec\u4e0a\u9ad8\u901f\uff1f\\n\\n\u4f5c\u8005\u663e\u800c\u6613\u89c1\u5730\u5ffd\u7565\u4e86\u4e00\u4e2a\u5173\u952e\u95ee\u9898\uff1a\u884c\u8f66\u5b89\u5168\u3002\\n\\n\u9a71\u4f7f\u4eba\u4eec\u7814\u53d1\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7684\u4e3b\u8981\u52a8\u529b\u51b3\u8ba1**\u4e0d\u662f**\u4e3a\u4e86\u8ffd\u6c42\u9ad8\u901f\uff0c**\u786e\u4fdd\u884c\u8f66\u5b89\u5168**\u662f\u975e\u5e38\u91cd\u8981\u7684\u76ee\u6807\u3002\u5176\u5b9e\uff0c\u201c\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u201d\u7684\u9650\u5b9a\u8bed\u201c\u65e0\u4eba\u201d\u5c31\u5df2\u7ecf\u6307\u51fa\u4e86\u5173\u952e\u6240\u5728\u3002\\n\\n\u201c\u65e0\u4eba\u201d\u610f\u5473\u7740\u4ec0\u4e48\uff1f\\n\\n\u7b2c\u4e00\uff0c**\u5c06\u4eba\u4ece\u53f8\u673a\u7684\u4f4d\u7f6e\u89e3\u653e\u51fa\u6765**\u3002\u8fd9\u4f1a\u5e26\u6765\u4fbf\u5229\u6027\uff0c\u4e5f\u80fd\u63d0\u5347\u7a7a\u95f4\u7684\u5229\u7528\u7387\u3002\\n\\n\u6709\u4e86\u65e0\u4eba\u9a7e\u9a76\u6280\u672f\uff0c\u4eba\u4eec\u65e0\u9700\u518d\u53bb\u5b66\u4e60\u9a7e\u9a76\u6280\u80fd\uff0c\u4e5f\u5c31\u4e0d\u4f1a\u6709\u201c\u6ca1\u6709\u53f8\u673a\u4e0d\u80fd\u51fa\u95e8\u201d\u7684\u60c5\u51b5\u53d1\u751f\u3002\u5728\u5f53\u524d\uff0c\u4e94\u4eba\u5ea7\u7684\u8f66\u8f86\u53f8\u673a\u8981\u5360\u6389\u4e00\u4e2a\u4f4d\u7f6e\uff0c\u4e00\u65e6\u65e0\u4eba\u9a7e\u9a76\u540e\uff0c\u81f3\u5c11\u53ef\u4ee5\u591a\u5750\u4e00\u4eba\uff08\u8bbe\u60f3\u4e00\u4e0b\uff0c\u82e5\u524d\u6392\u6ca1\u6709\u53f8\u673a\u7684\u64cd\u4f5c\u88c5\u7f6e\uff0c\u662f\u5426\u53ef\u4ee5\u53d8\u6210\u201c\u524d3+\u540e3\u201d\uff1f\uff09\u3002\\n\\n\u7b2c\u4e8c\uff0c**\u65e0\u4eba\u9a7e\u9a76\u610f\u5473\u7740\u5b89\u5168**\u3002\\n\\n\u7edd\u5927\u591a\u6570\u7684\u8f66\u7978\u90fd\u662f\u9a7e\u9a76\u4eba\u64cd\u4f5c\u4e0d\u5f53\u5f15\u8d77\u7684\uff0c\u8fd9\u662f\u4eba\u6027\u7684\u7f3a\u9677\u3002\u6709\u751f\u7406\u539f\u56e0\uff0c\u6bd4\u5982\uff0c\u4eba\u4e0d\u53ef\u80fd\u4fdd\u6301\u957f\u4e45\u7684\u6ce8\u610f\u529b\uff1b\u6709\u5fc3\u7406\u539f\u56e0\uff0c\u6bd4\u5982\uff0c\u6709\u7684\u53f8\u673a\u9ebb\u75f9\u5927\u610f\uff0c\u6216\u559c\u6b22\u8d85\u8f66\u7b49\u3002\\n\\n\u6240\u4ee5\uff0c\u628a\u8fd9\u4efd\u65e2\u7d2f\u4eba\u53c8\u6709\u5b89\u5168\u9690\u60a3\u7684\u5dee\u4e8b\u4ea4\u7ed9\u673a\u5668\uff0c\u4ea4\u7ed9\u7b97\u6cd5\uff0c\u53ef\u4ee5\u5927\u5927\u63d0\u9ad8\u884c\u8f66\u5b89\u5168\u3002\\n\\n\u7b2c\u4e09\uff0c**\u624d\u662f\u610f\u5473\u7740\u6548\u7387\u7684\u63d0\u5347**\u3002\\n\\n\u8bf7\u6ce8\u610f\uff0c\u6211\u8fd9\u91cc\u8bf4\u7684\u4e0d\u662f\u201c\u901f\u5ea6\u7684\u63d0\u5347\u201d\uff0c\u867d\u7136\u5728\u5f88\u591a\u65f6\u5019\u9ad8\u901f\u7b49\u540c\u4e8e\u9ad8\u6548\u7387\uff0c\u4f46\u662f\uff0c\u4f4e\u901f\u884c\u9a76\u7684\u8f66\u8f86\u4e5f\u53ef\u4ee5\u9ad8\u6548\u8fd0\u884c\u3002\\n\\n\u65e0\u4eba\u9a7e\u9a76\u5018\u82e5\u771f\u7684\u843d\u5730\u5b9e\u884c\uff0c\u7b2c\u4e00\u4e2a\u5931\u4e1a\u7684\u80af\u5b9a\u662f\u53f8\u673a\uff0c\u7b2c\u4e8c\u4e2a\u4f30\u8ba1\u5c31\u8f6e\u5230\u7ea2\u7eff\u706f\u4e86\u3002\u65e0\u4eba\u9a7e\u9a76\u8f66\u8f86\u4f1a\u63d0\u524d\u77e5\u9053\u524d\u65b9\u8def\u53e3\u7684\u72b6\u51b5\u800c\u51b3\u5b9a\u91c7\u53d6\u4ec0\u4e48\u6837\u7684\u884c\u8f66\u7b56\u7565\u3002\u6bd4\u5982\uff0c\u82e5\u6709\u884c\u4eba\u5728\u901a\u8fc7\u524d\u65b9\u8def\u53e3\uff0c\u8f66\u8f86\u7b97\u6cd5\u7cfb\u7edf\u4f1a\u6839\u636e\u4e8c\u8005\u7684\u901f\u5ea6\u6765\u9884\u5224\u662f\u5426\u6709\u4ea4\u6c47\uff0c\u4ece\u800c\u9009\u62e9\u662f\u52a0\u901f\u901a\u8fc7\uff0c\u8fd8\u662f\u51cf\u901f\u505c\u8f66\u8ba9\u884c\uff1b\u5f53\u4e24\u8f86\u8f66\u4ea4\u53c9\u901a\u8fc7\u540c\u4e00\u8def\u53e3\u65f6\uff0c\u4ea4\u901a\u7cfb\u7edf\u7b97\u6cd5\u4f1a\u63a5\u7ba1\u8f66\u8f86\u7684\u8c03\u5ea6\u5de5\u4f5c\uff0c\u51b3\u5b9a\u6bcf\u8f86\u8f66\u4ee5\u4ec0\u4e48\u8f66\u901f\u884c\u9a76\u800c\u4e0d\u4f1a\u53d1\u751f\u78b0\u649e\uff0c\u751a\u81f3\u53ef\u4ee5\u505a\u5230\u4e00\u8f86\u8f66\u521a\u521a\u901a\u8fc7\u8def\u53e3\uff0c\u800c\u53e6\u4e00\u8f86\u4e0e\u5b83\u201c\u64e6\u5c41\u800c\u8fc7\u201d \u2014\u2014 \u4e24\u8f86\u8f66\u7684\u8f66\u8eab\u95f4\u8ddd\u624d\u51e0\u5398\u7c73\uff01\\n\\n\u66f4\u4e0d\u4f1a\u51fa\u73b0\u4ea4\u53c9\u65b9\u5411\u8f66\u9053\u4e0a\u4e00\u8f86\u8f66\u90fd\u6ca1\u6709\u7684\uff0c\u800c\u53e6\u4e00\u8f86\u8f66\u5374\u5728\u50bb\u50bb\u5730\u7b49\u7ea2\u706f\u53d8\u7eff\uff01\u5c4a\u65f6\uff0c\u7ea2\u7eff\u706f\u518d\u662f\u5b89\u5168\u7684\u8c61\u5f81\uff0c\u800c\u6210\u4e86\u6548\u7387\u7684\u969c\u788d\u3002\u4f60\u8bf4\uff0c\u8fd8\u8981\u90a3\u52b3\u4ec0\u5b50\u5e72\u561b\uff1f\\n\\n\u4f5c\u8005\u8bf4\uff1a\\n\\n> \u672a\u6765\u9700\u8981\u9762\u5411\u65e0\u4eba\u8f66\uff0c\u8bbe\u8ba1\u201c\u8d85\u7ea7\u9ad8\u901f\u516c\u8def\u201d\uff0c\u5c06\u65e0\u4eba\u8f66\u548c\u6709\u4eba\u9a7e\u9a76\u7684\u6c7d\u8f66\u5206\u79bb\uff0c\u8981\u6c42\u6700\u4f4e\u65f6\u901f\u4e3a500\u5343\u7c73/\u5c0f\u65f6\u3002\\n\\n\u6211\u5f88\u60f3\u95ee\u95ee\uff0c\u8fd9\u79cd\u201c\u8d85\u7ea7\u9ad8\u901f\u516c\u8def\u201d\u5728\u54ea\u91cc\u4fee\u5efa\uff1f\\n\\n\u82e5\u662f\u57ce\u5e02\u9053\u8def\uff0c\u8981\u8fbe\u5230\u8fd9\u6837\u7684**\u6700\u4f4e\u65f6\u901f**\uff0c\u8f66\u8f86\u542f\u52a8\u9700\u8981\u591a\u4e45\uff0c\u7279\u522b\u662f\uff0c\u5236\u52a8\u9700\u8981\u591a\u4e45\uff1f\u8981\u77e5\u9053\uff0c\u8fd9\u662f8.3\u516c\u91cc/\u5206\u949f\u7684\u901f\u5ea6\uff0c\u8fd8\u662f\u201c\u8981\u6c42\u7684\u6700\u4f4e\u65f6\u901f\u201d\uff0c\u89c4\u6a21\u7a0d\u5c0f\u7684\u57ce\u5e02\u6050\u6015\u90fd\u6ca1\u6709\u8d44\u683c\u62e5\u6709\u8fd9\u79cd\u8def\uff0c\u8fd8\u6709\uff0c\u53bb\u7a0d\u8fd1\u7684\u5730\u65b9\u66f4\u6ca1\u6709\u8d44\u683c\u4e0a\u8fd9\u79cd\u201c\u8d85\u901f\u8def\u201d\uff0c\u56e0\u4e3a\u521a\u4e00\u4e0a\u53bb\u5c31\u5f97\u4e0b\u6765\u4e86\uff01\\n\\n\u663e\u7136\uff0c\u8fd9\u79cd\u201c\u8d85\u7ea7\u8def\u201d\u53ea\u80fd\u5efa\u5728\u57ce\u5e02\u4e4b\u95f4\u4e86\uff0c\u90a3\u5e02\u5185\u7684\u600e\u4e48\u529e\uff1f\u4eba\u4eec\u5bf9\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7684\u8ffd\u6c42\u53ef\u4e0d\u662f\u4e3a\u4e86\u53bb\u53e6\u4e00\u4e2a\u57ce\u5e02\u4e0a\u73ed\u7684\u3002\\n\\n\u6240\u4ee5\uff0c\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7684\u95ee\u9898\u51b3\u8ba1\u4e0d\u662f\u201c\u6362\u4e2a\u7ef4\u5ea6\uff0c\u5c06\u76ee\u5149\u4ece\u8f66\u8f86\u8f6c\u5411\u9053\u8def\u201d\u4fbf\u6709\u4e86\u89e3\u51b3\u4e4b\u9053\u3002\\n\\n\u8fd9\u6bb5\u6587\u7ae0\u4e5f\u4e0d\u662f\u4e00\u65e0\u662f\u5904\u3002\u4ece\u5386\u53f2\u7684\u89c6\u89d2\u6765\u770b\u5f85\u95ee\u9898\u3001\u5206\u6790\u95ee\u9898\uff0c\u4e0d\u65f6\u5730\u6362\u4e2a\u7ef4\u5ea6\u4e0e\u89c6\u89d2\uff0c\u8fd8\u662f\u975e\u5e38\u53ef\u53d6\u7684\u3002\\n\\n\u6709\u4e9b\u95ee\u9898\u786e\u5b9e\u662f\u8def\u7684\u95ee\u9898\u3002\u6bd4\u5982\uff0c\u5f53\u4f60\u4e0d\u505c\u5730\u6478\u77f3\u5934\u8fc7\u6cb3\uff0c\u5374\u603b\u662f\u642c\u8d77\u77f3\u5934\u7838\u811a\uff0c\u90a3\u5c31\u5e94\u8be5\u60f3\u60f3\u662f\u4e0d\u662f\u8be5\u6362\u6761\u8def\uff0c\u4e0d\u59a8\u8d70\u8d70\u6865\u3001\u4e58\u4e58\u8239\uff0c\u800c\u4e0d\u80fd\u603b\u51b2\u7740\u77f3\u5934\u8f83\u52b2\u3002\\n\\n\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7ec8\u4f1a\u4ee5\u4ec0\u4e48\u65b9\u5f0f\u8d70\u5165\u73b0\u5b9e\u7684\u751f\u6d3b\uff0c\u6211\u4eec\u7fd8\u9996\u4ee5\u5f85\u3002\u4e0d\u8bba\u600e\u6837\uff0c\u4eba\u7c7b\u5bf9\u4e8e\u672a\u6765\u7684\u7f8e\u597d\u5411\u5f80\u662f\u96be\u4ee5\u505c\u6b62\u7684\uff0c\u5728\u4f17\u591a\u7684\u61a7\u61ac\u5f53\u4e2d\uff0c\u4f30\u8ba1\u5f88\u591a\u4eba\u90fd\u4e0d\u66fe\u60f3\u5230\u7684\u4e00\u70b9\u662f\uff1a\u65e0\u4eba\u9a7e\u9a76\u6c7d\u8f66\u7684\u8f66\u5934\u4e0e\u8f66\u5c3e\u7684\u533a\u522b\u4f1a\u5f88\u6a21\u7cca\uff0c\u5373\u4fbf\u4f9d\u7136\u6709\u8f66\u5934\uff0c\u4e5f\u66f4\u591a\u7684\u662f\u8c61\u5f81\u610f\u4e49\u3002\\n\\n\u56e0\u4e3a\uff0c\u5728\u65e0\u4eba\u9a7e\u9a76\u6a21\u5f0f\u4e0b\uff0c\u5012\u8f66\u53ef\u4ee5\u548c\u524d\u8fdb\u4e00\u6837\u5feb\u3002\\n\\n![\u4e95\u86d9\u60ca\u68a6\u4eba](https://5shangzhi.github.io/img/frog.jpeg)"},{"id":"wusz-2022-06-13","metadata":{"permalink":"/blog/wusz-2022-06-13","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/\u9762\u5bf9\u66b4\u5f92\uff0c\u5f31\u8005\u4e34\u573a\u8be5\u5982\u4f55\u53cd\u5e94\uff1f.md","source":"@site/blog/\u9762\u5bf9\u66b4\u5f92\uff0c\u5f31\u8005\u4e34\u573a\u8be5\u5982\u4f55\u53cd\u5e94\uff1f.md","title":"\u9762\u5bf9\u66b4\u5f92\uff0c\u5f31\u8005\u4e34\u573a\u8be5\u5982\u4f55\u53cd\u5e94\uff1f","description":"\u770b\u89c1\u4e00\u7bc7\u6587\u7ae0\uff0c\u4e0d\u5c11\u4eba\u70b9\u8d5e\uff0c\u4f46\u6211\u770b\u4e86\u6709\u4e9b\u751f\u6c14\uff0c\u8ba4\u4e3a\u4f5c\u8005\u662f\u5728\u80e1\u626f\u3002","date":"2022-06-13T13:54:50.000Z","formattedDate":"2022\u5e746\u670813\u65e5","tags":[{"label":"\u4e95\u86d9\u6d45\u601d","permalink":"/blog/tags/\u4e95\u86d9\u6d45\u601d"},{"label":"\u4e95\u86d9\u60ca\u68a6\u4eba","permalink":"/blog/tags/\u4e95\u86d9\u60ca\u68a6\u4eba"},{"label":"\u5510\u5c71\u6253\u4eba\u4e8b\u4ef6","permalink":"/blog/tags/\u5510\u5c71\u6253\u4eba\u4e8b\u4ef6"},{"label":"\u5f31\u8005\u53cd\u6297","permalink":"/blog/tags/\u5f31\u8005\u53cd\u6297"},{"label":"\u4e34\u573a\u53cd\u5e94","permalink":"/blog/tags/\u4e34\u573a\u53cd\u5e94"}],"readingTime":15.18,"truncated":false,"authors":[{"name":"\u5434\u5c1a\u667a","title":"\u4e95\u86d9\u60ca\u68a6\u4eba","url":"https://github.com/5shangzhi","imageURL":"https://avatars.githubusercontent.com/u/103982059","key":"5shangzhi"}],"frontMatter":{"slug":"wusz-2022-06-13","title":"\u9762\u5bf9\u66b4\u5f92\uff0c\u5f31\u8005\u4e34\u573a\u8be5\u5982\u4f55\u53cd\u5e94\uff1f","authors":"5shangzhi","tags":["\u4e95\u86d9\u6d45\u601d","\u4e95\u86d9\u60ca\u68a6\u4eba","\u5510\u5c71\u6253\u4eba\u4e8b\u4ef6","\u5f31\u8005\u53cd\u6297","\u4e34\u573a\u53cd\u5e94"]},"prevItem":{"title":"\u662f\u8def\u7684\u95ee\u9898\uff1f","permalink":"/blog/wusz-2022-06-16"}},"content":"\u770b\u89c1\u4e00\u7bc7\u6587\u7ae0\uff0c\u4e0d\u5c11\u4eba\u70b9\u8d5e\uff0c\u4f46\u6211\u770b\u4e86\u6709\u4e9b\u751f\u6c14\uff0c\u8ba4\u4e3a\u4f5c\u8005\u662f\u5728\u80e1\u626f\u3002\\n\\n![](images/20220613/01.png)\\n\\n\u4f5c\u8005\u8fd8\u679a\u4e3e\u4e86\u90a3\u4e9b\u201c\u597d\u699c\u6837\u201d\u7684\u955c\u5934\uff1a\\n\\n![](images/20220613/02.png)\\n\\n\u6211\u5f88\u60f3\u95ee\u95ee\u4f5c\u8005\u662f\u5426\u4f1a\u4ee5\u6587\u4e2d\u7684**\u8fd9\u4e9b\u699c\u6837**\u6765\u6559\u81ea\u5df1\u7684\u5b69\u5b50\uff0c\u5982\u679c\u4e0d\u4f1a\uff0c\u4e3a\u4f55\u5982\u6b64\u6765\u5ffd\u60a0\u522b\u4eba\uff1f\\n\\n\u540c\u6837\u7684\u95ee\u9898\uff0c\u6211\u4e5f\u60f3\u95ee\u95ee\u90a3\u4e9b\u4e3a\u6587\u7ae0\u70b9\u8d5e\u7684\u4eba\u3002\u4f30\u8ba1\u6709\u76f8\u5f53\u4e00\u90e8\u5206\u4eba\u65e0\u6cd5\u76f4\u89c6\u81ea\u5df1\u7684\u5185\u5fc3\u3002\u4ed6\u4eec\u53ea\u662f\u6c89\u6d78\u5728\u201c\u52c7\u4e8e\u53cd\u6297\u201d\u3001\u201c\u4e0d\u754f\u5f3a\u66b4\u201d\u7684\u5927\u8bcd\u91cc\u9762\uff0c\u8111\u5b50\u91cc\u5374\u88ab\u4eba\u585e\u8fdb\u4e86\u7a3b\u8349\uff0c\u4e0d\u77e5\u4e0d\u89c9\u3002\\n\\n\u4f46\u51e1\u770b\u8fc7\u89c6\u9891\u7684\u4eba\u90fd\u4e0d\u4f1a\u5426\u8ba4\u8fd9\u4e00\u70b9\uff1a**\u53cc\u65b9\u5b9e\u529b\u60ac\u6b8a\uff0c\u65bd\u66b4\u8005\u7684\u6b66\u529b\u5b8c\u5168\u78be\u538b\u88ab\u8650\u8005**\u3002\u8fd9\u4e5f\u662f\u672c\u6587\u6240\u8ba8\u8bba\u8bdd\u9898\u7684\u4e00\u4e2a\u524d\u63d0\u6761\u4ef6\uff0c\u8bf7\u4e00\u5b9a\u7262\u8bb0\u8fd9\u4e00\u70b9 \u2014\u2014 \u5728\u6211\u53d1\u8d77\u7684\u6b64\u8bdd\u9898\u7684\u8ba8\u8bba\u4e2d\uff0c\u6709\u53c2\u4e0e\u8005\u65f6\u800c\u8df3\u51fa\u8fd9\u4e00\u9650\u5236\u6761\u4ef6\uff0c\u6211\u4e0d\u5f97\u4e0d\u53cd\u590d\u91cd\u7533\u3002\\n\\n\u5047\u8bbe\u60c5\u5883\u662f\u8fd9\u6837\uff0c\u53cc\u65b9\u5b9e\u529b\u60ac\u6b8a\uff0c\u65bd\u66b4\u8005\u5177\u6709\u78be\u538b\u5f0f\u7684\u6b66\u529b\u5a01\u80c1\uff0c\u800c\u4f60\u5973\u513f\u5c31\u662f\u90a3\u88ab\u9a9a\u6270\u7684\u5f31\u8005\uff0c\u4f60\u4f1a\u6559\u4f60\u5973\u513f\u4ee5\u90a3\u51e0\u4e2a\u5973\u5b50\u4e3a\u699c\u6837\u6765\u53cd\u51fb\u5417\uff1f\\n\\n\u4e0d\u59a8\u628a\u4f60\u5973\u513f\u60f3\u8c61\u6210\u90a3\u51e0\u4e2a\u5973\u5b50\uff0c**\u540e\u679c\u4f60\u4e5f\u770b\u5230\u4e86** \u2014\u2014 \u5982\u679c\u53ef\u4ee5\u91cd\u6765\u4e00\u6b21\uff0c\u4f60\u8fd8\u4f1a\u9f13\u52b1\u5979\u4eec\u90a3\u6837\u505a\u51fa**\u4e34\u573a\u53cd\u5e94**\u5417\uff1f\\n\\n\u6709\u4e0d\u5c11\u4eba\u8ba4\u4e3a\uff0c\u662f\u66b4\u5f92\u627e\u4e0a\u95e8\u7684\uff0c\u8fd9\u662f\u65e0\u5984\u4e4b\u707e\uff0c\u4f60\u907f\u65e0\u53ef\u907f\uff0c\u4e5f\u9000\u65e0\u53ef\u9000\uff0c\u53ea\u6709\u594b\u8d77\u53cd\u6297\u624d\u6709\u751f\u673a\u2026\u2026\\n\\n\u66fe\u56e0\u67d0\u4e8b\uff0c\u6211\u5199\u8fc7\u8fd9\u4e48\u4e00\u6bb5\uff1a\\n\\n> \u8bfb\u5386\u53f2\u65f6\u6211\u4eec\u5728\u8bfb\u4ec0\u4e48\uff1f\\n>\\n> \u7f57\u632f\u5b87\u8bf4\u4ed6\u66fe\u7ecf\u8bf7\u6559\u8fc7\u4e00\u4f4d\u5386\u53f2\u5b66\u8005\uff0c\u8bfb\u5386\u53f2\u8bfb\u5230\u4ec0\u4e48\u7a0b\u5ea6\u5c31\u7b97\u5165\u95e8\u4e86\u3002\u90a3\u5b66\u8005\u8bf4\uff0c\u201c\u5f53\u4f60\u4e0d\u518d\u8ba4\u4e3a\u8c01\u662f\u574f\u4eba\u3001\u8c01\u662f\u8822\u8d27\u7684\u65f6\u5019\uff0c\u5f53\u4f60\u80fd\u8bfb\u51fa\u6240\u6709\u4e8b\u4ef6\u5f53\u4e8b\u4eba\u7684\u2018\u4e0d\u5f97\u5df2\u2019\u7684\u65f6\u5019\uff0c\u5f53\u4f60\u770b\u5230\u4e8b\u5b9e\u7684\u590d\u6742\u6027\u7684\u65f6\u5019\uff0c\u5c31\u7b97\u662f\u8de8\u8fc7\u4e86\u5165\u95e8\u7684\u95e8\u69db\u201d\u3002\\n>\\n> \u4f5c\u4e3a\u201c\u5982\u4f55\u5165\u95e8\u201d\u7684\u8ba8\u8bba\uff0c\u6211\u57fa\u672c\u6301\u540c\u610f\u7684\u6001\u5ea6\u3002\u8fd9\u662f\u4e00\u79cd\u8de8\u8d8a\u65f6\u7a7a\u7684\u5171\u60c5\u80fd\u529b\uff0c\u8bfb\u53f2\u4eba\u52aa\u529b\u7f6e\u8eab\u4e8e\u5386\u53f2\u4eba\u7269\u7684\u60c5\u5883\u4e2d\uff0c\u7528\u5f53\u4e8b\u4eba\u7684\u89c6\u89d2\uff0c\u5207\u8eab\u4f53\u4f1a\u4e0e\u601d\u8003\u3002\u8881\u817e\u98de\u4e5f\u8bf4\u8fc7\u8fd9\u4e48\u4e00\u53e5\uff1a\u201c\u8bfb\u5386\u53f2\u5373\u662f\u8bfb\u4eba\u5fc3\u201d\uff0c\u66f4\u5b8f\u89c2\u4e00\u4e9b\u3002\\n>\\n> \u5165\u95e8\u4e4b\u540e\u5462\uff1f\u7f57\u632f\u5b87\u5e76\u6ca1\u6709\u8bb2\uff0c\u662f\u4ed6\u4eec\u7684\u8bdd\u9898\u5230\u6b64\u800c\u6b62\uff0c\u8fd8\u662f\u4ed6\u6ca1\u6709\u8fdb\u4e00\u6b65\u8bf4\uff0c\u6211\u4e0d\u5f97\u800c\u77e5\u3002\\n>\\n> \u4f46\u6211\u96be\u4ee5\u8ba4\u540c\uff1a\u201c\u8bfb\u51fa\u6240\u6709\u4e8b\u4ef6\u5f53\u4e8b\u4eba\u7684\u2018\u4e0d\u5f97\u5df2\u2019\u201d\u3002\u5982\u679c\u6211\u4eec\u4e8b\u4e8b\u90fd\u8ba4\u4e3a\u5f53\u4e8b\u4eba\u201c\u4e0d\u5f97\u5df2\u201d\uff0c\u90a3\u5386\u53f2\u8bfb\u6765\u53c8\u6709\u4f55\u7528\uff1f\u6211\u8ba4\u4e3a\uff0c\u201c\u4ee5\u53f2\u4e3a\u9274\u201d\uff0c\u90a3\u624d\u662f\u8bfb\u5386\u53f2\u7684\u610f\u4e49\u6240\u5728\u3002\\n>\\n> \u4ed6\u4eec\u5c31\u771f\u7684\u4e0d\u5f97\u5df2\u5417\uff1f\u5c31\u6ca1\u6709\u5176\u4ed6\u9009\u62e9\uff1f\\n>\\n> \u2026\u2026\\n>\\n> \u800c**\u6211\u4eec\u73b0\u5728\uff0c\u4fbf\u6d3b\u5728\u672a\u6765\u7684\u5386\u53f2\u5f53\u4e2d**\u3002\\n\\n6\u670810\u65e5\u51cc\u6668\uff0c\u5510\u5c71\u53d1\u751f\u7684\u90a3\u4e00\u5e55\u5df2\u7ecf\u8d70\u8fdb\u7684\u5386\u53f2\u3002\u5386\u53f2\u867d\u4e0d\u80fd\u5047\u8bbe\uff0c\u4f46\u6211\u4eec\u8bfb\u90a3\u6bb5\u5386\u53f2\uff0c\u5374\u53ef\u4ee5\u6765\u6b21\u601d\u60f3\u5b9e\u9a8c\uff0c\u4ee5\u8fd9\u4e9b\u8fc7\u5f80\u4e3a\u9274\uff0c\u4ece\u4e2d\u6c72\u53d6\u70b9\u4ec0\u4e48\uff0c\u6bd4\u5982\uff0c\u7ecf\u9a8c\u3001\u6559\u8bad\u3001\u603b\u7ed3\uff0c\u8fd9\u4e5f\u662f\u6211\u4eec\u5b66\u4e60\u5386\u53f2\u7684\u610f\u4e49\u3002\\n\\n\u90a3\u4e9b\u8ba4\u4e3a\u201c\u907f\u65e0\u53ef\u907f\uff0c\u4e5f\u9000\u65e0\u53ef\u9000\u201d\u4fbf\u662f\u8fdb\u5165\u4e86\u201c\u4e0d\u5f97\u5df2\u201d\u7684\u6f5c\u5728\u8bbe\u5b9a\u3002\u5982\u679c\u4f60\u4f9d\u7136\u6301\u7740\u8fd9\u6837\u7684\u60f3\u6cd5\uff0c\u4e8e\u4f60\u800c\u8a00\uff0c\u4e0b\u9762\u7684\u8ba8\u8bba\u5c31\u662f\u6d6a\u8d39\u65f6\u95f4\uff0c\u56e0\u4e3a\u4f60\u5df2\u7ecf\u6392\u9664\u4e86\u5176\u4ed6\u9009\u9879\uff0c\u601d\u7ef4\u662f\u5c01\u95ed\u7684\u3002\\n\\n\u57fa\u4e8e\u60c5\u5883\u8bbe\u5b9a\uff0c\u4eba\u4eec\u5f88\u5bb9\u6613\u5c06\u81ea\u5df1\uff08\u6216\u5973\u513f\uff09\u4ee3\u5165\u5973\u5b50\u7684\u89d2\u8272\u6765\u601d\u8003\u3002\u4e8e\u5171\u60c5\u800c\u8a00\uff0c\u8fd9\u662f\u6709\u597d\u5904\u7684\uff0c\u4f46\u4e00\u65e6\u5e26\u5165\uff0c\u65e2\u5b9a\u7684\u73b0\u573a\u753b\u9762\u4e5f\u5bb9\u6613\u5c01\u95ed\u601d\u8003\u8005\u7684\u5176\u4ed6\u8def\u5f84\uff0c\u66b4\u8d77\u53cd\u6297\u4fbf\u6210\u4e86\u552f\u4e00\u7684\u51fa\u8def\u3002\u6240\u4ee5\uff0c\u6211\u5047\u8bbe\u4e86\u4e00\u4e2a\u76f8\u4f3c\u7684\u8bdd\u9898\uff1a\\n\\n> \u90a3\u6362\u4e00\u4e2a\u95ee\u9898\uff1a\\n>\\n> \u5047\u8bbe\u60a8\u770b\u4e86\u4e00\u4e2a\u8001\u5e08\u66b4\u529b\u6bb4\u6253\u67d0\u5c0f\u5b66\u751f\u7684\u89c6\u9891\uff0c\u800c\u60a8\u4e5f\u6709\u5b69\u5b50\u5728\u8bfb\u5c0f\u5b66\uff0c\u51fa\u4e8e\u62c5\u5fc3\uff0c\u4f60\u4f1a\u600e\u4e48\u6559\u5bfc\u5b69\u5b50\uff1f\u62a1\u8d77\u94c5\u7b14\u76d2\u7838\u8001\u5e08\u4e48\uff1f\\n>\\n> \u518d\u91cd\u7533\u4e00\u4e0b\u6211\u7684\u95ee\u9898\u4e0e\u60c5\u5883\uff1a\\n>\\n> \u4f60\u4f1a\u5982\u4f55\u6559\u5bfc\u5b69\u5b50\u7ed9\u51fa\u4e34\u573a\u53cd\u5e94\uff1f\u5728\u53cc\u65b9\u5b9e\u529b\u60ac\u6b8a\uff0c\u5e76\u4e14\u5bf9\u65b9\u65bd\u66b4\u7684\u524d\u63d0\u4e0b\u3002\\n\\n\u4e3a\u4ec0\u4e48\u6211\u4e00\u518d\u5f3a\u8c03\u53cc\u65b9\u7684\u5b9e\u529b\u60ac\u6b8a\uff0c\u800c\u4e14\u662f\u5f31\u8005\u7684\u4e34\u573a\u53cd\u5e94\uff1f\u56e0\u4e3a\u8fd9\u76f4\u63a5\u5173\u7cfb\u5230\u5f31\u8005\u7684\u88ab\u4f24\u5bb3\u7a0b\u5ea6\u3002\u5f31\u8005\u7684\u53cd\u6297\u4f1a\u62db\u81f4\u65bd\u66b4\u8005\u66f4\u51f6\u72e0\u7684\u653b\u51fb\u3002\\n\\n\u5728\u8fd9\u8d77\u4e8b\u4ef6\u4e2d\uff0c\u5e0c\u671b\u5927\u5bb6\u6ce8\u610f\u5230\u4e86\u66b4\u5f92\u8e29\u5973\u751f\u5934\u7684\u753b\u9762\u3002\u5973\u751f\u672c\u5df2\u5012\u5730\uff0c\u65e0\u529b\u53cd\u6297\uff0c\u4e3a\u4ec0\u4e48\u8fd8\u8981\u8e29\u5979\u7684\u5934\uff1f\u4e00\u6765\u662f\u65bd\u66b4\u8005\u6cc4\u6124\uff1b\u4e8c\u6765\u8fd9\u52a8\u4f5c\u8fd8\u6709\u7279\u522b\u542b\u4e49\uff0c\u662f\u5bf9\u5f31\u8005\u6562\u53cd\u6297\u8fdb\u884c\u62a5\u590d\uff0c\u6467\u6bc1\u5f31\u8005\u7684\u610f\u5fd7\uff08\u4eba\u7528\u5927\u8111\u6765\u601d\u7ef4\uff0c\u5934\u662f\u610f\u5fd7\u529b\u7684\u8c61\u5f81\uff09\u3002\\n\\n\u5728\u601d\u8003\u5982\u4f55\u6559\u5bfc\u5b69\u5b50\u7ed9\u51fa\u4e34\u573a\u53cd\u5e94\u7684\u65f6\u5019\uff0c\u4e0d\u59a8\u5148\u786e\u5b9a\u4e00\u4e2a\u539f\u5219\uff1a**\u529b\u6c42\u907f\u514d\u5b69\u5b50\u906d\u53d7\u5927\u7684\u4f24\u5bb3\uff0c\u4f24\u5bb3\u8d8a\u5c0f\u8d8a\u597d**\u3002\\n\\n\u56e0\u4e3a\u6709\u7684\u8eab\u4f53\u4f24\u5bb3\u4e00\u65e6\u53d1\u751f\u662f\u4e0d\u53ef\u9006\u7684\uff0c\u6216\u8005\u4ee3\u4ef7\u5f88\u9ad8\u3002\u6bd4\u5982\uff0c\u762b\u75ea\u3001\u773c\u778e\u3002\u4e00\u65e6\u53d7\u4f24\u81f4\u6b8b\uff0c\u8fd9\u662f\u4e8b\u540e\u600e\u4e48\u90fd\u96be\u4ee5\u627e\u8865\u7684\u3002\\n\\n\u6211\u79f0\u4e4b\u4e3a\uff1a\u4eba\u8eab\u4f24\u5bb3\u6700\u5c0f\u539f\u5219\u3002\u8fd9\u65e2\u662f\u5236\u5b9a\u7b56\u7565\u7684\u539f\u5219\uff0c\u4e5f\u662f\u601d\u8003\u95ee\u9898\u7684\u7ec8\u6781\u76ee\u7684\u3002\u4ee5\u6b64\u51fa\u53d1\uff0c\u4e0b\u4e00\u6b65\u624d\u662f\u5236\u5b9a\u4e34\u573a\u5e94\u5bf9\u7b56\u7565\u3002\\n\\n\u6709\u9053\u662f\u201c\u541b\u5b50\u4e0d\u7acb\u5371\u5899\u4e4b\u4e0b\u201d\uff0c\u8fd9\u53e5\u8bdd\u9664\u4e86\u5f3a\u8c03\u201c\u7ad9\u4f4d\u201d\u4ee5\u5916\uff0c\u8fd8\u6709\u4e00\u4e2a\u610f\u601d\uff0c\u5c31\u662f\u4e0e\u5371\u9669\u4fdd\u6301\u8ddd\u79bb\u3002\u4e5f\u5c31\u662f\u8bf4\uff0c\u4f60\u9996\u5148\u5f97\u60f3\u5230\u7684\u662f\u4e00\u4e2a\u5b57 \u2014\u2014 \u8dd1 \u2014\u2014 \u5c31\u50cf\u611f\u89c9\u5230\u5730\u9707\u65f6\u7684\u7b2c\u4e00\u53cd\u5e94\u4e00\u6837\uff0c\u6492\u817f\u5c31\u8dd1\uff0c\u8dd1\u5230\u5b89\u5168\u7684\u5730\u65b9\u3002\\n\\n\u8fd8\u8bb0\u5f97\u8bdd\u9898\u8bbe\u5b9a\u7684\u524d\u63d0\u4e48\uff1f\u654c\u5f3a\u6211\u5f31\uff0c\u5b9e\u529b\u60ac\u6b8a \u2014\u2014 \u4f60\u5f88\u53ef\u80fd\u8dd1\u4e0d\u6389\u7684\uff01\u5c31\u50cf\u4e8b\u4ef6\u4e2d\u7684\u5973\u5b50\uff0c\u66b4\u5f92\u5df2\u7ecf\u5c06\u5979\u5835\u5728\u5ea7\u4f4d\u4e0a\u4e86\u3002\u4f3c\u4e4e\u771f\u7684\u6ca1\u6709\u53ef\u9009\u9879\u4e86\uff0c\u53ea\u5269\u4e0b\u80cc\u6c34\u4e00\u6218\uff0c\u6284\u8d77\u9152\u74f6\u5b50\u2026\u2026\\n\\n\u53ea\u80fd\u8fd9\u6837\uff1f\u5c31\u6ca1\u6709\u5176\u4ed6\u529e\u6cd5\u4e86\uff1f\\n\\n\u6211\u770b\u4e86\u4e00\u4e9b\u76f8\u5173\u7684\u6587\u7ae0\uff0c\u6ca1\u6709\u4e00\u4e2a\u5f88\u597d\u7684\u7b54\u6848\uff0c\u76f4\u81f3\u770b\u4e86\u5f90\u6653\u51ac\u7684\u89c6\u9891\u3002\\n\\n![](images/20220613/03.png)\\n\u6211\u8ba4\u4e3a\u4ed6\u7684\u5e94\u5bf9\u7b56\u7565\u662f\u6700\u4e13\u4e1a\u7684\uff1a\\n\\n**\u5bfb\u6c42\u5e2e\u52a9\uff01**\\n\\n\u56e0\u4e3a\uff0c\u4e00\uff0c\u4f60\u6253\u4e0d\u8fc7\uff1b\u4e8c\uff0c\u4f60\u8dd1\u4e0d\u8fc7\u3002\\n\\n\u5bfb\u6c42**\u8c01**\u7684\u5e2e\u52a9\uff1f\\n\\n\u9996\u5148\uff0c**\u5bfb\u6c42\u5e97\u5bb6\u7684\u5e2e\u52a9**\u3002\u56e0\u4e3a\u5728\u5e97\u91cc\u53d1\u751f\u6253\u4eba\u4e8b\u4ef6\uff0c\u5e97\u5bb6\u8d1f\u6709\u8fde\u5e26\u8d23\u4efb\uff0c\u6240\u4ee5\uff0c\u4e16\u754c\u4e0a\u4efb\u4f55\u4e00\u4e2a\u5e97\u5bb6\u90fd\u4e0d\u5e0c\u671b\u5e97\u91cc\u53d1\u751f\u8fd9\u79cd\u4e8b\u3002\\n\\n\u5982\u679c\u65bd\u66b4\u8005\u5c31\u662f\u5e97\u4e3b\u6216\u5e97\u91cc\u7684\u4eba\uff0c\u600e\u4e48\u529e\uff1f\\n\\n**\u54ea\u91cc\u4eba\u591a\u53bb\u54ea\u91cc\uff01**\\n\\n\u56e0\u4e3a\u201c\u4eba\u591a\u52bf\u4f17\u201d\uff0c\u4ed6\u4eec\u5373\u4f7f\u4e0d\u6562\u51fa\u624b\u5e2e\u5fd9\uff0c\u4f46\u4e5f\u4f1a\u5e2e\u62e6\u7740\u3002\u5f90\u6653\u51ac\u8fd8\u4e3e\u4e86\u4f8b\u5b50\uff0c\u6bd4\u5982\uff0c\u770b\u89c1\u5305\u53a2\u91cc\u9762\u6709\u4e03\u516b\u4e2a\u4eba\u8fc7\u751f\u65e5\uff0c\u5c31\u4e00\u8fb9\u558a\u201c\u6551\u547d\uff01\u6709\u4eba\u6740\u4eba\u5566\uff01\u201d\uff0c\u4e00\u8fb9\u51b2\u8fdb\u53bb\u6251\u5728\u4ed6\u4eec\u684c\u5b50\u4e0a\uff0c\u62b1\u4f4f\u91cc\u9762\u7684\u4eba\u2026\u2026\u56e0\u4e3a\u4ed6\u4eec\u4eba\u591a\uff0c\u5373\u4f7f\u4e0d\u6562\u53cd\u51fb\uff0c\u4e5f\u4e00\u5b9a\u4f1a\u529d\u963b\u8bd5\u56fe\u65bd\u66b4\u7684\u4eba\u3002\u8fd9\u65f6\uff0c\u4f60\u5c31\u6709\u673a\u4f1a\u62a5\u8b66\uff0c\u6709\u673a\u4f1a\u9003\u8131\u3002\\n\\n\u53e6\u5916\uff0c\u5f90\u6653\u51ac\u8fd8\u7279\u522b\u63d0\u53ca\uff0c\u8ba9\u5973\u5b69\u7ec3\u4e60\u640f\u51fb\u4e0d\u662f\u89e3\u51b3\u4e4b\u9053\uff0c\u90a3\u79cd\u501f\u6b64\u4e8b\u4ef6\u547c\u5401\u4f60\u53bb\u5b66\u62f3\u7684\u90fd\u662f\u5ffd\u60a0\uff0c\u4e0d\u503c\u5f97\u4f60\u53bb\u5b66\uff0c\u56e0\u4e3a\u4e00\u4e2a\u5973\u5b50\u518d\u600e\u4e48\u5389\u5bb3\u4e5f\u6253\u4e0d\u8fc7\u4e09\u56db\u4e2a\u58ee\u6c49\uff0c\u90a3\u4e0d\u662f\u5728\u62f3\u53f0\uff0c\u684c\u6905\u677f\u51f3\u9152\u74f6\u4ec0\u4e48\u5bb6\u4f19\u90fd\u6709\uff0c\u5b83\u4eec\u65e2\u662f\u969c\u788d\u7269\uff0c\u4e5f\u662f\u6b66\u5668\uff0c\u4e00\u65e6\u996d\u83dc\u9152\u6c34\u6492\u4e86\u4e00\u5730\uff0c\u90a3\u5730\u9762\u4e5f\u548c\u62f3\u53f0\u6216\u516b\u89d2\u7b3c\u91cc\u7684\u4e0d\u4e00\u6837\u3002\\n\\n\u6240\u4ee5\uff0c**\u884c\u4e4b\u6709\u6548**\u7684\u7b56\u7565\u5c31\u662f\u4e24\u6761\uff08\u5176\u5b9e\u662f\u4e00\u6761\uff09\uff1a\\n\\n1. \u5bfb\u6c42\u5e2e\u52a9\uff01\\n2. \u54ea\u91cc\u4eba\u591a\u53bb\u54ea\u91cc\uff08\u5bfb\u6c42\u5e2e\u52a9\uff09\uff01\\n\\n\u4f60\u770b\uff0c\u5f53\u5973\u5b50\u88ab\u9a9a\u6270\u65f6\uff0c\u62a1\u8d77\u9152\u74f6\u5f00\u5e72\u4e0d\u662f\u552f\u4e00\u7684\u9009\u9879\uff0c\u66f4\u4e0d\u662f\u4e0d\u5f97\u5df2\u7684\u9009\u9879\u3002\u5979\u53ef\u4ee5\u548c\u5973\u4f34\u4eec\u4e00\u8d77\u5927\u558a\uff1a\\n\\n\u201c\u8001\u677f\uff0c\u6551\u547d\u5440\uff01\u6709\u6d41\u6c13\u9a9a\u6270\u6211\u4eec\uff0c\u6551\u547d\u5440\uff01\u201d\\n\\n\u8bf7\u6ce8\u610f\u6211\u6240\u5efa\u8bae\u7684**\u547c\u6551\u6b21\u5e8f**\uff0c\u8fd9\u662f\u6709\u5fc3\u7406\u5b66\u77e5\u8bc6\u4e0e\u903b\u8f91\u652f\u6491\u7684\uff1a\\n\\n1. **\u8001\u677f**\uff1a\u5728\u566a\u6742\u7684\u573a\u6240\uff0c\u82e5\u4f60\u5728\u5fd9\u81ea\u5df1\u7684\u4e8b\uff0c\u4f1a\u81ea\u52a8\u5c4f\u853d\u5468\u8fb9\u7684\u58f0\u97f3\uff0c\u4f46\u82e5\u6709\u4eba\u8c08\u5230\u4f60\u540d\u5b57\uff0c\u4f60\u4f1a\u81ea\u52a8\u6355\u6349\uff0c\u5f15\u8d77\u4f60\u7684\u6ce8\u610f\u3002\u6240\u4ee5\uff0c\u7b2c\u4e00\u53e5\u4e00\u5b9a\u662f\u547c\u53eb\u5bf9\u65b9\u7684\u540d\u5b57\u6216\u79f0\u8c13\uff0c\u5f15\u8d77\u4ed6\u7684\u6ce8\u610f\u3002\\n2. **\u6551\u547d\u5440**\uff1a\u4e0e\u4e0a\u9762\u9053\u7406\u76f8\u540c\uff0c\u6211\u4eec\u6240\u6709\u4eba\u90fd\u4f1a\u5bf9\u8fd9\u4e2a\u8bcd\u6c47\u654f\u611f\uff0c\u54ea\u6015\u5468\u8fb9\u5608\u6742\uff0c\u6211\u4eec\u4e5f\u4f1a\u81ea\u52a8\u6355\u6349\u5230\u8fd9\u4e2a\u58f0\u97f3\u3002\u5c24\u5176\u662f\u8001\u677f\uff0c\u4ed6\u80fd\u7acb\u523b\u660e\u767d\u4f60\u558a\u4ed6\u4e0d\u662f\u4e3a\u4e86\u4e0a\u83dc\u6162\u7684\u95ee\u9898\u3002\\n3. **\u6709\u6d41\u6c13\u9a9a\u6270\u6211\u4eec**\uff1a\u8fd9\u662f\u5411\u6240\u6709\u4eba\u89e3\u91ca\u4e8b\u60c5\u7684\u539f\u59d4\uff0c\u4f60\u662f\u88ab\u6b3a\u8d1f\u7684\uff0c\u800c\u5bf9\u65b9\u662f\u6076\u4eba\u3002\u8fd9\u662f\u4e00\u5b9a\u8981\u4ea4\u4ee3\u7684\uff0c\u8ba9\u65c1\u89c2\u8005\u5206\u6e05\u7acb\u573a\uff0c\u8fc5\u901f\u7ad9\u961f\u3002\\n4. **\u6551\u547d\u5440**\uff1a\u7b2c\u4e8c\u4e2a\u201c\u6551\u547d\u5440\uff01\u201d\u4e0d\u80fd\u7701\u7565\uff0c\u8fd9\u662f\u518d\u6b21\u8868\u660e\u610f\u56fe\u3002\u201c\u547c\u53eb\u5bf9\u8c61-\u610f\u56fe-\u89e3\u91ca\u539f\u59d4-\u610f\u56fe\u201d\u3002\u7b2c\u4e00\u4e2a\u662f\u907f\u514d\u4ed6\u4ee5\u4e3a\u662f\u666e\u901a\u7684\u4e8b\uff0c\u7b2c\u4e8c\u4e2a\u662f\u50ac\u4fc3\uff0c\u8fd9\u4e8b\u975e\u5e38\u7d27\u6025\uff0c\u8d76\u5feb\u6765\uff01\u4e24\u4e2a\u6551\u547d\u4e00\u5b9a\u8981\u5927\u58f0\uff0c\u5bf9\u66b4\u5f92\u5f62\u6210\u9707\u6151\u529b\u3002\\n\\n\u91cd\u70b9\u89e3\u91ca\u7b2c3\u6761\uff0c\u8fd9\u6761\u4e07\u4e07\u4e0d\u53ef\u5c11\uff0c\u4e5f\u662f\u6211\u5728\u590d\u76d8\u4e8b\u4ef6\u6240\u83b7\u5f97\u7684\u6559\u8bad\u3002\u6211\u4eec\u4e8b\u540e\u770b\u89c6\u9891\u624d\u77e5\u9053\u4e8b\u4ef6\u53d1\u751f\u7684\u7ecf\u8fc7\uff0c\u8fd9\u662f\u201c\u4e0a\u5e1d\u89c6\u89d2\u201d\uff0c\u8981\u77e5\u9053\uff0c\u4e8b\u53d1\u65f6\u5728\u573a\u7684\u5176\u4ed6\u4eba\u5b8c\u5168\u662f\u61f5\u7684\uff0c\u4ed6\u4eec\u57fa\u672c\u90fd\u5728\u53cc\u65b9\u6253\u8d77\u6765\u4ee5\u540e\u624d\u611f\u77e5\u5230\uff0c\u5728\u6b64\u4e4b\u524d\uff0c\u4ed6\u4eec\u7684\u6ce8\u610f\u529b\u90fd\u5728\u5403\u5403\u559d\u559d\u4e0a\uff0c\u6216\u8005\u5728\u540c\u4f34\u8eab\u4e0a\uff0c\u54ea\u91cc\u77e5\u9053\u662f\u8fd9\u7537\u7684\u5148\u9a9a\u6270\u5973\u7684\uff1f\u6240\u4ee5\uff0c\u5973\u7684\u5fc5\u987b\u89e3\u91ca\u539f\u59d4\uff0c\u5bf9\u65b9\u662f\u574f\u4eba\uff0c\u5728\u9a9a\u6270\u6211\uff01\u65c1\u89c2\u8005\u624d\u597d\u7ad9\u5728\u4f60\u8fd9\u4e00\u65b9\u3002\\n\\n\u5982\u679c\u90a3\uff08\u4e9b\uff09\u5973\u5b50\u662f\u8fd9\u4e48\u7ed9\u51fa\u4e34\u573a\u53cd\u5e94\u7684\uff0c\u7ed3\u679c\u4f1a\u4e0d\u4f1a\u4e24\u6837\uff1f\\n\\n\u6709\u7684\u670b\u53cb\u53ef\u80fd\u4f1a\u8bf4\uff0c\u4f60\u8bf4\u7684\u8fd9\u4e9b\u6ca1\u7528\uff0c\u5927\u73af\u5883\u4e0d\u597d\u7684\u8bdd\uff0c\u90fd\u662f\u5f92\u52b3\u3002\u6211\u5927\u4f53\u662f\u540c\u610f\u7684\uff0c\u8fd9\u662f**\u793e\u4f1a\u4e0e\u4e2a\u4f53**\u7684\u5173\u7cfb\u3002\u793e\u4f1a\u5c31\u50cf\u6d69\u701a\u7684\u5927\u6d77\uff0c\u4e2a\u4f53\u662f\u4e00\u53f6\u6241\u821f\u3002\u98ce\u5e73\u6d6a\u9759\u65f6\u662f\u96be\u4ee5\u7ffb\u8239\u7684\uff1b\u800c\u4e00\u65e6\u6ce2\u6d9b\u6c79\u6d8c\uff0c\u90a3\u7ffb\u8239\u7684\u51e0\u7387\u5c31\u5927\u5927\u589e\u52a0\uff1b\u82e5\u662f\u51fa\u73b0\u6ed4\u5929\u5927\u6d6a\uff0c\u90a3\u6240\u6709\u7684\u64cd\u821f\u6280\u80fd\u90fd\u5c06\u5931\u6548\uff0c\u53ea\u80fd\u542c\u5929\u7531\u547d\u4e86\u3002\\n\\n\u6211\u4eec\u4e00\u5b9a\u8981\u77e5\u9053\uff0c**\u53ea\u6709\u5927\u73af\u5883\u53d8\u597d\u4e86**\uff0c\u6cd5\u6cbb\u7cbe\u795e\u5f97\u5230\u666e\u904d\u6027\u5730\u843d\u5b9e\uff0c\u72af\u7f6a\u7387\u624d\u4f1a\u5927\u5e45\u964d\u4f4e\uff0c**\u56fd\u6c11\u7684\u5b89\u5168\u7cfb\u6570\u624d\u4f1a\u5927\u5927\u63d0\u9ad8**\u3002\u800c\u8981\u60f3\u5927\u73af\u5883\u53d8\u597d\uff0c\u653f\u5e9c\u662f\u5173\u952e\u6240\u5728\u3002\u5c31\u4e0d\u5c55\u5f00\u8bf4\u4e86\u3002\\n\\n\u5f53\u524d\uff0c\u6211\u662f\u4ece\u4e2a\u4f53\u51fa\u53d1\uff0c\u63a2\u8ba8\u5728\u6ce2\u6d9b\u6c79\u6d8c\u65f6\u5982\u4f55\u589e\u52a0\u751f\u8fd8\u7684\u6982\u7387\uff0c\u5e76\u5c3d\u91cf\u5c06\u4e2a\u4f53\u7684\u88ab\u4f24\u5bb3\u7a0b\u5ea6\u964d\u5230\u6700\u5c0f\u3002\\n\\n\u6700\u540e\uff0c\u7ed9\u5f90\u6653\u51ac\u7684\u8bdd\u6253\u4e00\u4e2a\u8865\u4e01\uff1a\u4e0d\u662f\u8bf4\u7ec3\u4e60\u640f\u51fb\u4e00\u70b9\u7528\u6ca1\u6709\uff0c\u800c\u662f\u8bf4\u5f53\u4f60\u9762\u5bf9\u5b9e\u529b\u8fdc\u8fdc\u5f3a\u8fc7\u4f60\u7684\u66b4\u5f92\uff0c\u4f60\u53cd\u51fb\u7684\u6548\u7528\u6781\u5176\u6709\u9650\uff0c\u751a\u81f3\u53ef\u4ee5\u5ffd\u7565\u4e0d\u8ba1\u3002\u7ec3\u4e60\u640f\u51fb\u5bf9\u901a\u5e38\u60c5\u51b5\u662f\u6709\u7528\u7684\uff0c\u6bd4\u5982\u4f60\u7ec3\u5f97\u8180\u5927\u8170\u5706\u7684\uff0c\u5e26\u7740\u5973\u4f34\u5728\u5916\u9762\u5403\u996d\uff0c\u88ab\u4eba\u9a9a\u6270\u7684\u6982\u7387\u4e5f\u4f1a\u964d\u4f4e\u3002\u4f46\u8bf4\u5230\u901a\u5e38\u60c5\u51b5\uff0c\u4e8e\u666e\u901a\u4eba\u800c\u8a00\uff0c\u8fd8\u662f\u201c\u541b\u5b50\u4e0d\u7acb\u5371\u5899\u4e4b\u4e0b\u201d\u66f4\u6709\u610f\u4e49\uff1a\u5c3d\u91cf\u522b\u5728\u4e00\u4e9b\u65f6\u6bb5\u5916\u51fa\uff08\u6bd4\u5982\u6df1\u591c\u51cc\u6668\uff09\uff0c\u5c3d\u91cf\u907f\u514d\u53bb\u4e00\u4e9b\u51b2\u7a81\u9891\u53d1\u7684\u573a\u6240\uff08\u5927\u6392\u6863\u3001\u6b4c\u821e\u5385\u3001\u591c\u603b\u4f1a\u7b49\uff09\u3002\u8bf4\u5230\u5e95\uff0c\u4e2a\u4eba\u7684\u5b89\u5168\u4e0e\u201c\u65f6\u7a7a\u201d\u76f8\u5173\uff0c**\u66f4\u4e0e\u4e2a\u4eba\u7684\u9009\u62e9\u5f3a\u76f8\u5173** \u2014\u2014 \u201c\u7acb\u201d\u4e0e\u201c\u4e0d\u7acb\u201d\u4e8e\u5371\u5899\uff0c\u4fbf\u662f\u9009\u62e9\u3002\\n\\n\u8bb0\u4f4f\uff0c\u5f53\u4f60\u88ab\u66b4\u5f92\u9a9a\u6270\u6216\u5a01\u80c1\u65f6\uff0c\u4e0d\u8981\u81ea\u5df1\u5148\u5c06\u6240\u6709\u7684\u8def\u90fd\u5835\u6b7b\uff0c\u8ba4\u4e3a\u53ea\u6709\u62a1\u8d77\u9152\u74f6\u8fd9\u4e00\u6761\u8def\uff0c\u4f60\u8fd8\u6709\u9009\u62e9\u7684\uff0c\u9996\u5148\u8981**\u5bfb\u6c42\u5e2e\u52a9**\uff1a\\n\\n\u201c\u8001\u677f\uff0c**\u6551\u547d\u5440\uff01** \u6709\u6d41\u6c13\u9a9a\u6270\u6211\uff08\u4eec\uff09\uff0c**\u6551\u547d\u5440\uff01**\u201d\\n\\n\u63a5\u7740\uff1a**\u54ea\u91cc\u4eba\u591a\u53bb\u54ea\u513f\uff01**\\n\\n\u524d\u8f66\u8986\u8f99\uff0c\u5386\u53f2\u53ef\u9274\u3002\\n\\n![\u4e95\u86d9\u60ca\u68a6\u4eba](https://5shangzhi.github.io/img/frog.jpeg)"}]}')}}]);